changeSet.sql:
ALTER TABLE answer_attempt DROP CONSTRAINT fk_answer_attempt_student_attempt;
ALTER TABLE student_attempt DROP CONSTRAINT pk_student_attempt;
ALTER TABLE student_attempt DROP COLUMN id;

-- I leave it start with 1 but if table already has data, it can lead to PK violation. Can we set it to max(id) + 1?
ALTER TABLE student_attempt ADD id BIGINT IDENTITY(1,1) NOT NULL;
ALTER TABLE student_attempt ADD CONSTRAINT pk_student_attempt PRIMARY KEY (id);
ALTER TABLE answer_attempt ADD CONSTRAINT fk_answer_attempt_student_attempt
FOREIGN KEY (student_attempt_id) REFERENCES student_attempt(id);

